using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class BudgetModeConfiguration : IEntityTypeConfiguration<BudgetMode>{public void Configure(EntityTypeBuilder<BudgetMode> builder){builder.ToTable("budget_modes");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("mode_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Code).HasMaxLength(50).IsRequired();builder.Property(e => e.Name).HasMaxLength(100).IsRequired();builder.Property(e => e.ShortDescription).HasMaxLength(200).IsRequired();builder.Property(e => e.IconCode).HasMaxLength(30);builder.Property(e => e.ColorTheme).HasMaxLength(7);builder.Property(e => e.EstimatedCostMinMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.EstimatedCostMaxMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.Rules).HasColumnType("jsonb").HasDefaultValueSql("'{}'::jsonb");builder.HasIndex(e => e.Code).IsUnique();}}
